module top_module(A, B, SUB, SUM);input [3:0] A, B;
  input SUB;
  output reg [3:0] SUM;  // Change output to reg type

  reg [3:0] X_temp;

  always @(*) begin
    if(SUB == 0) begin
      X_temp = A + B;
      SUM = X_temp;
    end
    else begin
      X_temp = A - B;
      SUM = X_temp;
    end
  end
endmodule
